INSERT INTO public.feature_definitions (id, key, description, default_enabled, created_at, updated_at, name, category, value_type) VALUES
  ('cdf17e84-5e6d-4ca0-8504-b97cc43ab2a6'::uuid, 'notification', 'Controls notification behavior (in-app notifications, delivery rules, and what notification modules are enabled).', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:15:05.468848+00'::timestamptz, 'Notification', 'core', 'boolean'),
  ('6a0da102-0686-4998-9066-6b9620159c3c'::uuid, 'reward_system', 'Controls gamification and rewards features (points, rewards, achievements, and anything tied to engagement incentives).', false, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:15:17.760159+00'::timestamptz, 'Reward System', 'engagement', 'boolean'),
  ('34e6407f-7727-4aa4-95d0-3ca1781750e3'::uuid, 'storage_quota_mb', 'A plan limit that caps total storage capacity available to an institution, measured in MB.', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:15:34.172685+00'::timestamptz, 'Storage quota (MB)', 'limits', 'bigint'),
  ('2c54ce09-a3aa-4cd9-acde-bc3232d58048'::uuid, 'student', 'Controls student-facing features and student permissions (what students can access and do).', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:16:22.970723+00'::timestamptz, 'Student', 'core', 'boolean'),
  ('4fc8bf94-34a3-4806-aef9-c5a8c6511549'::uuid, 'task', 'Controls task/exercise features (creating tasks, assigning them, completing them, and task-related flows).', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:16:35.516146+00'::timestamptz, 'Task', 'core', 'boolean'),
  ('3885f9b4-b2da-4175-b468-38d6c62a0700'::uuid, 'teacher', 'Controls teacher-facing features and teacher permissions (authoring, managing classes/courses/games, and admin capabilities within teaching scope).', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:16:47.024786+00'::timestamptz, 'Teacher', 'core', 'boolean'),
  ('153ae2e7-c154-449d-bf55-4e52239f82ca'::uuid, 'deepl_integration_enabled', 'Controls whether the DeepL Writer API can be used for text simplification in Game Components', false, '2026-04-09 17:38:57.33499+00'::timestamptz, '2026-04-09 17:38:57.33499+00'::timestamptz, 'DeepL Integration', 'integrations', 'boolean'),
  ('e7cdc9d6-b7da-43f1-a18a-8569b61a9b34'::uuid, 'drag_drop_math', 'Controls whether the Drag and Drop Math game type is available for teachers to create and students to play.', true, '2026-04-09 17:40:19.468652+00'::timestamptz, '2026-04-09 18:02:14.452492+00'::timestamptz, 'Drag & Drop Math', 'games', 'boolean'),
  ('f6e579d7-2c95-449e-9815-0390d22e455c'::uuid, 'open_question', 'Controls whether the Open Question game type is available.', true, '2026-04-09 17:42:31.638422+00'::timestamptz, '2026-04-09 18:02:29.649196+00'::timestamptz, 'Open Question', 'games', 'boolean'),
  ('e8a958df-ea2b-4039-a53e-2011a97ee184'::uuid, 'game_image_pin', 'Enables the Game Image Pin question type, where learners answer by placing one or more pins on an image (for example, marking a location, identifying an area, or selecting the correct point). The system can validate responses using target zones and tolerance rules, and can optionally provide hints and feedback.', true, '2026-04-09 18:10:38.237409+00'::timestamptz, '2026-04-09 18:10:38.237409+00'::timestamptz, 'Image Pin', 'games', 'boolean'),
  ('fddb08df-491c-4688-aa69-153ea134d844'::uuid, 'game_multiplayer_enabled', 'Determines if games can be played against each other or in a class setting (multiplayer/collaborative mode).', true, '2026-04-09 18:11:28.945142+00'::timestamptz, '2026-04-09 18:11:28.945142+00'::timestamptz, 'Multiplayer', 'collaboration', 'boolean'),
  ('86bc5746-f454-49ff-a2f4-7e018097a244'::uuid, 'max_students', 'A plan limit that caps how many student accounts can exist or be active under an institution.', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 19:55:29.524363+00'::timestamptz, 'Maximal Students', 'limits', 'integer'),
  ('2c6e2816-eed5-40cd-86fb-3597d3d0f445'::uuid, 'max_teachers', 'A plan limit that caps how many teacher accounts can exist or be active under an institution.', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 19:55:44.608898+00'::timestamptz, 'Maximal Teachers', 'limits', 'integer'),
  ('da4b2d93-7ed1-48ba-866a-dd09f94223ea'::uuid, 'max_classrooms', 'A plan limit that caps how many classrooms an institution can create/use.', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 19:56:02.254481+00'::timestamptz, 'Maximal classrooms', 'limits', 'integer'),
  ('c753e432-13a5-4cd2-9deb-9b8e9de81212'::uuid, 'max_design_section_image_pins', 'A plan limit tied to “design squares” usage (most likely your Image Pin / rectangle creation budget). It caps how many design squares can be used.', true, '2026-04-07 10:38:49.311384+00'::timestamptz, '2026-04-09 19:56:17.190653+00'::timestamptz, 'Maximal Design Squares used In Image', 'limits', 'integer'),
  ('d5d0aa9b-1f18-449f-9eb3-6307986ae29f'::uuid, 'calendar', 'Controls calendar-related functionality and availability across the product (for example, whether users can use built-in scheduling or calendar views).', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:11:29.757256+00'::timestamptz, 'Calendar', 'core', 'boolean'),
  ('94e00933-ea9f-4c34-9a33-297afc8f8edf'::uuid, 'chat', 'Controls the in-app messaging experience (direct messages, group/class chat, and related permissions).', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:11:42.396197+00'::timestamptz, 'Chat', 'core', 'boolean'),
  ('7e12d638-c4de-4182-9f91-38206220a72f'::uuid, 'classroom', 'Controls classroom features like creating classrooms, joining, managing classroom membership, and classroom-specific workflows.', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:11:52.09116+00'::timestamptz, 'Classroom', 'core', 'boolean'),
  ('647658b4-ae37-451a-9ed7-7f7e1f5503eb'::uuid, 'cloud_storage', 'Controls file storage features (uploads, asset handling, and storage-related limits/behaviors).', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:12:06.098656+00'::timestamptz, 'Cloud storage', 'infrastructure', 'boolean'),
  ('18e26d63-bb23-4ad8-b56f-e27744ea1618'::uuid, 'course', 'Controls course management features (creating courses, structuring content, and course-level delivery features).', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:12:25.768992+00'::timestamptz, 'Course', 'core', 'boolean'),
  ('2aeac58c-5da5-47c4-9e1d-e8386c154970'::uuid, 'game_studio', 'Controls access to the game authoring and gameplay system (creating game content, publishing, and running games).', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:12:39.859507+00'::timestamptz, 'Game Studio', 'core', 'boolean'),
  ('a98d8df0-62ce-4818-a0c9-2323fb04adf6'::uuid, 'institution', 'Controls institution-level features (tenant setup, institution profile/config, and institution-scoped governance settings).', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:13:13.138484+00'::timestamptz, 'Institution', 'core', 'boolean'),
  ('1e0e440e-db67-4047-b09e-c09c7cd2ec58'::uuid, 'note', 'Controls the notes/lesson content system (creating and using notes, interactive note blocks, and related capabilities).', true, '2026-04-06 14:42:56.106111+00'::timestamptz, '2026-04-09 17:14:54.428398+00'::timestamptz, 'Note', 'core', 'boolean')
